import { Logger } from "@elgato/streamdeck";
import axios from "axios";

export class FaviconHandler{
    private logger!: Logger;

    constructor (logger: Logger){
        this.logger = logger;
    }

    MANUAL_FAVICONS_OVERRIDES: Record<string, string> = {
        "github.com": "data:image/png;base64,",
        "youtube.com": "data:image/png;base64,",
        "bing.com": "data:image/png;base64,",
        "chatgpt.co": "data:image/png;base64,",
        "openai.com": "data:image/png;base64,",
        "amazon.com": "data:image/png;base64,",
        "pinterest.com": "data:image/png;base64,",
        "autohotkey.com": "data:image/png;base64,",
        "edge://newtab/": "data:image/png;base64,",
        "music.apple.com": "data:image/png;base64,",
        "icons8.com": "data:image/png;base64,",
        "chromedevtools.github.io": "data:image/png;base64,"
    }

    FAVICONS_FOR_GITHUB: Record<string, string> = {
        "jaba-campaign-api": "data:image/png;base64,",
        "jaba-composite-api": "data:image/png;base64,",
        "jaba-users-api": "data:image/png;base64,",
        "jaba-organizations-api": "data:image/png;base64,",
        "jaba-social-media-api": "data:image/png;base64,",
        "jaba-google-calendar-etl": "data:image/png;base64,",
        "jaba-outlook-calendar-etl": "data:image/png;base64,"
    }

    faviconCache: Record<string,string> = {};

    async getFavicon(fullUrl: string): Promise<string>{
        try{
            // this.logger.debug(`getting favicon for ${fullUrl}`);
            const url = new URL(fullUrl);
            let domain = url.hostname.toLowerCase();
            if (domain.startsWith("www.")) domain = domain.slice(4);

            // this.logger.debug(`hostname: ${domain}`);
            if(domain === 'chatgpt.com') domain = 'chatgpt.co'

            if(fullUrl === 'edge://newtab/'){
                return this.MANUAL_FAVICONS_OVERRIDES['edge://newtab/']
            }

            if(domain === 'github.com'){
                const repoName = this.extractGithubRepoName(fullUrl);
                if(!(repoName in this.FAVICONS_FOR_GITHUB)){
                    return this.MANUAL_FAVICONS_OVERRIDES['github.com'];
                }
                return this.FAVICONS_FOR_GITHUB[repoName];
            }

            if(domain in this.MANUAL_FAVICONS_OVERRIDES){
                return this.MANUAL_FAVICONS_OVERRIDES[domain];
            }

            if(domain in this.faviconCache){
                return this.faviconCache[domain];
            }

            this.logger.debug('making request for favicon for url ' + domain);
            const rawFavicon = await axios.get<ArrayBuffer>(
                `https://img.logo.dev/${domain}?token=pk_Gb5xYqzMT2KthP8ESZj36g&size=144&format=png&retina=true`,
                { responseType: "arraybuffer", headers: { "User-Agent": "Mozilla/5.0" } }
            );
            const faviconBase64 = 'data:image/png;base64,' + Buffer.from(rawFavicon.data).toString("base64");

            this.faviconCache[domain] = faviconBase64;

            return faviconBase64;
        } catch (error) {
            return "";
        }
    }

    extractGithubRepoName(fullUrl: string): string{
        try{
            const { pathname } = new URL(fullUrl);
            const parts = pathname.split('/').filter(Boolean);
            return parts[1] ?? "";
        } catch {
            return "";
        }
    }
}